/**
 * Razorpay Payment Gateway Integration Service (Client)
 *
 * Security:
 * - Never store or use Razorpay key secret in the browser.
 * - All Razorpay REST operations are proxied through Firebase Functions.
 */

import { httpsCallable } from 'firebase/functions'
import { functions } from './firebase'

// Storage keys (client-only preferences + local transaction cache)
const RAZORPAY_SETTINGS_KEY = 'razorpay_settings'
const RAZORPAY_TRANSACTIONS_KEY = 'razorpay_transactions'
const RAZORPAY_STATUS_CACHE_KEY = 'razorpay_server_status_cache'

export interface RazorpaySettings {
  // Public, non-secret metadata/preferences. Secrets are stored server-side only.
  autoGenerateLinks: boolean
  enabledMethods: {
    upi: boolean
    card: boolean
    netbanking: boolean
    wallet: boolean
  }
  businessName?: string
  logoUrl?: string
}

// Backwards compatibility alias
export type RazorpayConfig = RazorpaySettings

export interface RazorpayServerStatus {
  configured: boolean
  keyId: string
  isLiveMode: boolean
  validated: boolean
  message?: string
}

export interface RazorpayOrder {
  id: string
  entity: string
  amount: number
  amount_paid: number
  amount_due: number
  currency: string
  receipt: string
  status: 'created' | 'attempted' | 'paid'
  notes: Record<string, string>
  created_at: number
}

export interface RazorpayPaymentLink {
  id: string
  short_url: string
  amount: number
  currency: string
  status: 'created' | 'paid' | 'cancelled' | 'expired'
  description: string
  customer: {
    name?: string
    email?: string
    contact?: string
  }
  notes: Record<string, string>
  created_at: number
  expire_by?: number
}

export interface RazorpayTransaction {
  id: string
  razorpayOrderId?: string
  razorpayPaymentId?: string
  razorpayPaymentLinkId?: string
  invoiceId: string
  invoiceNumber: string
  amount: number
  currency: string
  status: 'pending' | 'processing' | 'completed' | 'failed' | 'refunded'
  paymentMethod?: string
  customerName?: string
  customerPhone?: string
  customerEmail?: string
  shortUrl?: string
  createdAt: string
  updatedAt: string
  paidAt?: string
  errorMessage?: string
}

const ensureFunctionsReady = () => {
  if (!functions) {
    throw new Error('Firebase functions not initialized')
  }
}

function safeParseJson<T>(raw: string | null): T | null {
  try {
    return raw ? (JSON.parse(raw) as T) : null
  } catch {
    return null
  }
}

function getDefaultSettings(): RazorpaySettings {
  return {
    autoGenerateLinks: true,
    enabledMethods: { upi: true, card: true, netbanking: true, wallet: true }
  }
}

// Preferences (non-secret)
export function getRazorpaySettings(): RazorpaySettings | null {
  const stored = safeParseJson<any>(localStorage.getItem(RAZORPAY_SETTINGS_KEY))
  if (!stored || typeof stored !== 'object') return null

  // Strip any legacy secrets that may still exist in localStorage.
  const { keySecret: _ignoredKeySecret, webhookSecret: _ignoredWebhookSecret, ...rest } = stored

  const enabledMethods = rest.enabledMethods && typeof rest.enabledMethods === 'object'
    ? {
        upi: Boolean(rest.enabledMethods.upi),
        card: Boolean(rest.enabledMethods.card),
        netbanking: Boolean(rest.enabledMethods.netbanking),
        wallet: Boolean(rest.enabledMethods.wallet)
      }
    : getDefaultSettings().enabledMethods

  return {
    autoGenerateLinks: Boolean(rest.autoGenerateLinks ?? true),
    enabledMethods,
    businessName: typeof rest.businessName === 'string' ? rest.businessName : undefined,
    logoUrl: typeof rest.logoUrl === 'string' ? rest.logoUrl : undefined
  }
}

export function saveRazorpaySettings(settings: RazorpaySettings): boolean {
  try {
    localStorage.setItem(RAZORPAY_SETTINGS_KEY, JSON.stringify(settings))
    return true
  } catch {
    return false
  }
}

// Backwards compatible API surface for settings page
export function getRazorpayConfig(): RazorpayConfig {
  return getRazorpaySettings() || getDefaultSettings()
}

export function saveRazorpayConfig(config: RazorpayConfig): boolean {
  return saveRazorpaySettings(config)
}

export function getCachedRazorpayServerStatus(): RazorpayServerStatus | null {
  return safeParseJson<RazorpayServerStatus>(localStorage.getItem(RAZORPAY_STATUS_CACHE_KEY))
}

export async function fetchRazorpayServerStatus(): Promise<RazorpayServerStatus> {
  ensureFunctionsReady()
  const callable = httpsCallable(functions!, 'getRazorpayConfigStatus')
  const response = await callable({})
  const status = response.data as RazorpayServerStatus
  localStorage.setItem(RAZORPAY_STATUS_CACHE_KEY, JSON.stringify(status))
  return status
}

// Synchronous helper (best-effort, based on cached server status)
export function isRazorpayConfigured(): boolean {
  return Boolean(getCachedRazorpayServerStatus()?.configured)
}

export async function validateRazorpayKeys(_keyId: string, _keySecret: string): Promise<{ valid: boolean; message: string }> {
  try {
    const status = await fetchRazorpayServerStatus()
    const ok = Boolean(status.configured)
    return { valid: ok, message: status.message || (ok ? 'Razorpay configured' : 'Razorpay not configured') }
  } catch (error) {
    return { valid: false, message: error instanceof Error ? error.message : 'Failed to validate Razorpay configuration' }
  }
}

export async function testRazorpayConnection(): Promise<{ success: boolean; message: string }> {
  try {
    const status = await fetchRazorpayServerStatus()
    const ok = Boolean(status.configured)
    return { success: ok, message: status.message || (ok ? 'Connection successful' : 'Razorpay not configured') }
  } catch (error) {
    return { success: false, message: error instanceof Error ? error.message : 'Failed to connect to Razorpay' }
  }
}

// Transactions (client-local tracking)
export function getRazorpayTransactions(): RazorpayTransaction[] {
  const stored = safeParseJson<RazorpayTransaction[]>(localStorage.getItem(RAZORPAY_TRANSACTIONS_KEY))
  return Array.isArray(stored) ? stored : []
}

export function saveRazorpayTransaction(transaction: RazorpayTransaction): boolean {
  try {
    const transactions = getRazorpayTransactions()
    const existingIndex = transactions.findIndex(t => t.id === transaction.id)
    if (existingIndex >= 0) {
      transactions[existingIndex] = { ...transactions[existingIndex], ...transaction }
    } else {
      transactions.unshift(transaction)
    }
    localStorage.setItem(RAZORPAY_TRANSACTIONS_KEY, JSON.stringify(transactions))
    return true
  } catch {
    return false
  }
}

export function getTransactionsForInvoice(invoiceId: string): RazorpayTransaction[] {
  return getRazorpayTransactions().filter(t => t.invoiceId === invoiceId)
}

export function getRazorpayStats(): {
  totalTransactions: number
  completedTransactions: number
  pendingTransactions: number
  failedTransactions: number
  totalAmountCollected: number
  totalAmountPending: number
} {
  const transactions = getRazorpayTransactions()
  return {
    totalTransactions: transactions.length,
    completedTransactions: transactions.filter(t => t.status === 'completed').length,
    pendingTransactions: transactions.filter(t => t.status === 'pending' || t.status === 'processing').length,
    failedTransactions: transactions.filter(t => t.status === 'failed').length,
    totalAmountCollected: transactions.filter(t => t.status === 'completed').reduce((sum, t) => sum + t.amount, 0),
    totalAmountPending: transactions
      .filter(t => t.status === 'pending' || t.status === 'processing')
      .reduce((sum, t) => sum + t.amount, 0)
  }
}

