// Legacy export: create a minimal order object for callers that expect RazorpayOrder.
export async function createRazorpayOrder(
  amount: number,
  receipt: string,
  notes: Record<string, string> = {}
): Promise<RazorpayOrder | null> {
  const order = await createRazorpayPosOrder({ amount, currency: 'INR', receipt, notes })
  return {
    id: order.orderId,
    entity: 'order',
    amount: order.amount,
    amount_paid: 0,
    amount_due: order.amount,
    currency: order.currency,
    receipt,
    status: 'created',
    notes,
    created_at: Math.floor(Date.now() / 1000)
  }
}

export async function createPaymentLink(
  invoiceId: string,
  invoiceNumber: string,
  amount: number,
  customerName?: string,
  customerPhone?: string,
  customerEmail?: string,
  description?: string,
  _expiresInDays: number = 7
): Promise<RazorpayPaymentLink | null> {
  const callbackUrl = `${window.location.origin}/payment-success`

  const paymentLink = await createRazorpayPaymentLink({
    amount,
    currency: 'INR',
    description: description || `Payment for Invoice ${invoiceNumber}`,
    customer: {
      name: customerName,
      contact: customerPhone ? customerPhone.replace(/[^0-9+]/g, '') : undefined,
      email: customerEmail
    },
    notes: {
      invoice_id: invoiceId,
      invoice_number: invoiceNumber
    },
    referenceId: invoiceId,
    callbackUrl,
    callbackMethod: 'get'
  })

  const transaction: RazorpayTransaction = {
    id: `txn_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`,
    razorpayPaymentLinkId: paymentLink.paymentLinkId,
    invoiceId,
    invoiceNumber,
    amount,
    currency: 'INR',
    status: 'pending',
    customerName,
    customerPhone,
    customerEmail,
    shortUrl: paymentLink.shortUrl,
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString()
  }
  saveRazorpayTransaction(transaction)

  return {
    id: paymentLink.paymentLinkId,
    short_url: paymentLink.shortUrl,
    amount: paymentLink.amount,
    currency: paymentLink.currency,
    status: (paymentLink.status || 'created') as RazorpayPaymentLink['status'],
    description: description || `Payment for Invoice ${invoiceNumber}`,
    customer: { name: customerName, email: customerEmail, contact: customerPhone },
    notes: { invoice_id: invoiceId, invoice_number: invoiceNumber },
    created_at: Math.floor(Date.now() / 1000)
  }
}

