// Update transaction status after payment (client-local)
export async function updateTransactionStatus(
  paymentLinkId: string,
  status: RazorpayTransaction['status'],
  paymentId?: string,
  paymentMethod?: string
): Promise<boolean> {
  try {
    const transactions = getRazorpayTransactions()
    const transaction = transactions.find(t => t.razorpayPaymentLinkId === paymentLinkId)
    if (!transaction) return false

    transaction.status = status
    transaction.updatedAt = new Date().toISOString()

    if (paymentId) transaction.razorpayPaymentId = paymentId
    if (paymentMethod) transaction.paymentMethod = paymentMethod
    if (status === 'completed') transaction.paidAt = new Date().toISOString()

    localStorage.setItem(RAZORPAY_TRANSACTIONS_KEY, JSON.stringify(transactions))

    if (status === 'completed') {
      await updateInvoicePaymentStatus(transaction.invoiceId, transaction.amount, paymentMethod || 'razorpay')
    }

    return true
  } catch {
    return false
  }
}

async function updateInvoicePaymentStatus(
  invoiceId: string,
  amount: number,
  paymentMethod: string
): Promise<boolean> {
  try {
    const invoicesData = localStorage.getItem('thisai_crm_invoices')
    if (!invoicesData) return false

    const invoices = JSON.parse(invoicesData)
    const invoiceIndex = invoices.findIndex((inv: any) => inv.id === invoiceId)
    if (invoiceIndex === -1) return false

    const invoice = invoices[invoiceIndex]
    const currentPaid = invoice.paidAmount || invoice.payment?.paidAmount || 0
    const newPaidAmount = currentPaid + amount
    const total = invoice.grandTotal || invoice.total || 0

    invoices[invoiceIndex] = {
      ...invoice,
      paidAmount: newPaidAmount,
      paymentStatus: newPaidAmount >= total ? 'paid' : 'partial',
      paymentMode: paymentMethod,
      payment: {
        ...invoice.payment,
        paidAmount: newPaidAmount,
        status: newPaidAmount >= total ? 'completed' : 'partial',
        mode: paymentMethod
      },
      updatedAt: new Date().toISOString()
    }

    localStorage.setItem('thisai_crm_invoices', JSON.stringify(invoices))
    return true
  } catch {
    return false
  }
}

// Load Razorpay Checkout script (public)
export function loadRazorpayScript(): Promise<boolean> {
  return new Promise(resolve => {
    if ((window as any).Razorpay) {
      resolve(true)
      return
    }

    const script = document.createElement('script')
    script.src = 'https://checkout.razorpay.com/v1/checkout.js'
    script.async = true
    script.onload = () => resolve(true)
    script.onerror = () => resolve(false)
    document.body.appendChild(script)
  })
}

// Open Razorpay Checkout (requires keyId, provided by server status or create order response)
export async function openRazorpayCheckout(
  orderId: string,
  amount: number,
  invoiceNumber: string,
  customerName?: string,
  customerEmail?: string,
  customerPhone?: string,
  onSuccess?: (response: any) => void,
  onError?: (error: any) => void
): Promise<void> {
  const status = await fetchRazorpayServerStatus()
  if (!status.keyId) {
    throw new Error('Razorpay not configured')
  }

  const scriptLoaded = await loadRazorpayScript()
  if (!scriptLoaded) {
    throw new Error('Failed to load Razorpay script')
  }

  const prefs = getRazorpaySettings()

  const options = {
    key: status.keyId,
    amount,
    currency: 'INR',
    name: prefs?.businessName || 'Sandra ERP',
    description: `Payment for Invoice ${invoiceNumber}`,
    order_id: orderId,
    prefill: {
      name: customerName || '',
      email: customerEmail || '',
      contact: customerPhone || ''
    },
    notes: {
      invoice_number: invoiceNumber
    },
    handler: function (response: any) {
      if (onSuccess) onSuccess(response)
    },
    modal: {
      ondismiss: function () {
        // no-op
      }
    }
  }

  const razorpay = new (window as any).Razorpay(options)
  razorpay.on('payment.failed', function (response: any) {
    if (onError) onError(response.error)
  })
  razorpay.open()
}

export async function openRazorpayCheckoutWithOrder(params: {
  keyId: string
  orderId: string
  amount: number
  currency?: string
  name?: string
  description?: string
  prefill?: { name?: string; email?: string; contact?: string }
  notes?: Record<string, string>
}): Promise<RazorpayCheckoutResult> {
  const scriptLoaded = await loadRazorpayScript()
  if (!scriptLoaded) {
    throw new Error('Failed to load Razorpay script')
  }

  return new Promise((resolve, reject) => {
    const options = {
      key: params.keyId,
      amount: params.amount,
      currency: params.currency || 'INR',
      name: params.name || getRazorpaySettings()?.businessName || 'Sandra ERP',
      description: params.description || 'Payment',
      order_id: params.orderId,
      prefill: params.prefill || {},
      notes: params.notes || {},
      handler: (response: any) => {
        resolve({
          orderId: response.razorpay_order_id,
          paymentId: response.razorpay_payment_id,
          signature: response.razorpay_signature
        })
      },
      modal: {
        ondismiss: () => {
          reject(new Error('Payment cancelled'))
        }
      }
    }

    const razorpay = new (window as any).Razorpay(options)
    razorpay.on('payment.failed', (response: any) => {
      reject(response.error || new Error('Payment failed'))
    })
    razorpay.open()
  })
}

export function formatRazorpayAmount(amountInPaise: number): string {
  return `INR ${(amountInPaise / 100).toLocaleString('en-IN', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`
}

